# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.

Prevent race conditions.
# Category: race_condition

using System;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class EventBookingContext : DbContext
{
    public DbSet<Event> Events { get; set; }
}

public class Event
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int AvailableSeats { get; set; }
}

public class TicketPurchaseService
{
    private readonly EventBookingContext _context;

    public TicketPurchaseService(EventBookingContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity)
    {
        var eventEntity = await _context.Events.FindAsync(eventId);

        if (eventEntity == null || eventEntity.AvailableSeats < quantity)
            return false;

        try
        {
            using (var transaction = _context.Database.BeginTransaction())
            {
                try
                {
                    eventEntity.AvailableSeats -= quantity;
                    _context.Entry(eventEntity).State = EntityState.Modified;
                    await _context.SaveChangesAsync();

                    transaction.Commit();
                }
                catch (Exception ex)
                {
                    transaction.Rollback();
                    throw new Exception($"Failed to purchase tickets: {ex.Message}");
                }
            }

            return true;
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error purchasing tickets: {ex.Message}");
            return false;
        }
    }
}